{
var seed = GetInt(parameters, "seed", context.Seed);
var density = Math.Clamp(GetInt(parameters, "density", 8), 4, 20);
var threadThickness = GetFloat(parameters, "threadThickness", 0.4f);
var weaveType = GetChoice(parameters, "weaveType", "plain");
var warpColor = GetColor(parameters, "warpColor", Color.FromRgb(160, 100, 60));
var weftColor = GetColor(parameters, "weftColor", Color.FromRgb(140, 80, 50));
var colorVar = GetFloat(parameters, "colorVariation", 0.15f);
var softness = GetFloat(parameters, "softness", 0.5f);
var fuzziness = GetFloat(parameters, "fuzziness", 0.3f);
var glossiness = GetFloat(parameters, "glossiness", 0.2f);
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var wR = warpColor.R / 255f; var wG = warpColor.G / 255f; var wB = warpColor.B / 255f;
var fR = weftColor.R / 255f; var fG = weftColor.G / 255f; var fB = weftColor.B / 255f;

// Thread spacing (UV units)
var threadSpacing = 1f / density;

// Pre-compute thread colors with per-thread variation
var warpThreads = new (float r, float g, float b)[density];
var weftThreads = new (float r, float g, float b)[density];
for (var i = 0; i < density; i++)
{
    var wv = (HashToUnit(i, seed, 111) - 0.5f) * colorVar;
    var fv = (HashToUnit(i * 7, seed + 50, 222) - 0.5f) * colorVar;
    warpThreads[i] = (
        Math.Clamp(wR + wv, 0f, 1f),
        Math.Clamp(wG + wv * 0.85f, 0f, 1f),
        Math.Clamp(wB + wv * 0.7f, 0f, 1f)
    );
    weftThreads[i] = (
        Math.Clamp(fR + fv, 0f, 1f),
        Math.Clamp(fG + fv * 0.85f, 0f, 1f),
        Math.Clamp(fB + fv * 0.7f, 0f, 1f)
    );
}

// Build weave pattern lookup
// true = warp on top, false = weft on top
var pattern = new bool[density, density];
for (var y = 0; y < density; y++)
{
    for (var x = 0; x < density; x++)
    {
        pattern[x, y] = weaveType switch
        {
            "twill" => (x + y) % 3 == 0,       // Diagonal twill
            "satin" => (x * 3 + y * 5) % 7 < 3, // Irregular satin
            _ => (x + y) % 2 == 0              // Plain weave
        };
    }
}

// Thread cross-section profile (smooth bump)
static float ThreadProfile(float t, float thickness, float softness)
{
    // t is distance from thread center in [0, 1]
    // Returns 1 at center, 0 outside thread
    var halfThick = thickness * 0.5f;
    if (t > halfThick) return 0f;
    var normalized = t / halfThick;
    var smooth = normalized * normalized * (3f - 2f * normalized); // smoothstep
    var soft = 1f - smooth;
    return Lerp(soft, 1f - normalized, 1f - softness * 0.5f);
}

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Thread coordinates
    var threadX = u * density;
    var threadY = v * density;

    // Current thread indices (with wrapping for tiling)
    var tx = ((int)MathF.Floor(threadX) % density + density) % density;
    var ty = ((int)MathF.Floor(threadY) % density + density) % density;

    // Local position within a thread cell (0..1)
    var localX = threadX - MathF.Floor(threadX);
    var localY = threadY - MathF.Floor(threadY);

    // Distance to thread centers
    var distWarp = MathF.Abs(localX - 0.5f); // warp runs vertically
    var distWeft = MathF.Abs(localY - 0.5f); // weft runs horizontally

    // Normalize by spacing (so thickness is relative to cell size)
    var warpProfile = ThreadProfile(distWarp, threadThickness, softness);
    var weftProfile = ThreadProfile(distWeft, threadThickness, softness);

    // Determine which thread is on top based on weave pattern
    var warpOnTop = pattern[tx, ty];

    // Fuzziness: add noise to thread edges
    if (fuzziness > 0f)
    {
        var fuzzNoise = TileableFractalNoise(
            u * density * 4f, v * density * 4f,
            Math.Max(1, size / 2), 2, 0.5f, 2f, seed + 100);
        var fuzzOffset = (fuzzNoise - 0.5f) * fuzziness * 0.15f;

        if (warpOnTop)
            warpProfile = Math.Clamp(warpProfile + fuzzOffset, 0f, 1f);
        else
            weftProfile = Math.Clamp(weftProfile + fuzzOffset, 0f, 1f);
    }

    // Sample thread colors
    var warpCol = warpThreads[tx];
    var weftCol = weftThreads[ty];

    float r, g, b;

    if (warpOnTop && warpProfile > 0f)
    {
        // Warp thread visible on top
        var coverage = warpProfile;

        // Weft shows through slightly
        var weftThrough = weftProfile * (1f - coverage) * 0.5f;

        r = Math.Clamp(warpCol.r * coverage + weftCol.r * weftThrough, 0f, 1f);
        g = Math.Clamp(warpCol.g * coverage + weftCol.g * weftThrough, 0f, 1f);
        b = Math.Clamp(warpCol.b * coverage + weftCol.b * weftThrough, 0f, 1f);
    }
    else if (!warpOnTop && weftProfile > 0f)
    {
        // Weft thread visible on top
        var coverage = weftProfile;

        // Warp shows through slightly
        var warpThrough = warpProfile * (1f - coverage) * 0.5f;

        r = Math.Clamp(weftCol.r * coverage + warpCol.r * warpThrough, 0f, 1f);
        g = Math.Clamp(weftCol.g * coverage + warpCol.g * warpThrough, 0f, 1f);
        b = Math.Clamp(weftCol.b * coverage + warpCol.b * warpThrough, 0f, 1f);
    }
    else
    {
        // Gap between threads or hidden thread — show blended under-thread
        var totalWarp = warpProfile * (warpOnTop ? 0.3f : 1f);
        var totalWeft = weftProfile * (warpOnTop ? 1f : 0.3f);
        var total = totalWarp + totalWeft;

        if (total > 0f)
        {
            r = (warpCol.r * totalWarp + weftCol.r * totalWeft) / total;
            g = (warpCol.g * totalWarp + weftCol.g * totalWeft) / total;
            b = (warpCol.b * totalWarp + weftCol.b * totalWeft) / total;
        }
        else
        {
            // Background between threads — interpolate between thread colors
            r = Lerp(warpCol.r, weftCol.r, 0.5f) * 0.6f;
            g = Lerp(warpCol.g, weftCol.g, 0.5f) * 0.6f;
            b = Lerp(warpCol.b, weftCol.b, 0.5f) * 0.6f;
        }
    }

    // Gloss / sheen effect
    if (glossiness > 0f)
    {
        var sheenNoise = TileableFractalNoise(
            u * density * 2f, v * density * 2f,
            Math.Max(1, size / 2), 1, 0.5f, 2f, seed + 200);
        var sheen = sheenNoise * glossiness * 0.15f;
        r = Math.Clamp(r + sheen, 0f, 1f);
        g = Math.Clamp(g + sheen * 0.9f, 0f, 1f);
        b = Math.Clamp(b + sheen * 0.8f, 0f, 1f);
    }

    // Surface detail
    var detailNoise = TileableFractalNoise(
        u * density * 6f, v * density * 6f,
        Math.Max(1, size / 3), 2, 0.5f, 2.5f, seed + 300);
    var detail = (detailNoise - 0.5f) * 0.06f;
    r = Math.Clamp(r + detail, 0f, 1f);
    g = Math.Clamp(g + detail * 0.9f, 0f, 1f);
    b = Math.Clamp(b + detail * 0.85f, 0f, 1f);

    // Brightness and contrast
    r = Math.Clamp(r + brightness, 0f, 1f);
    g = Math.Clamp(g + brightness, 0f, 1f);
    b = Math.Clamp(b + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        r = (r - 0.5f) * factor + 0.5f;
        g = (g - 0.5f) * factor + 0.5f;
        b = (b - 0.5f) * factor + 0.5f;
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
